import React from "react";
import KitsContainer from "../../Helpers/FormContainer";
import type { ITreeSelect } from "@lmb/kitsconcerto-types";
import { TreeSelect } from "@lmb/kitsconcertomobile";
import { ClHelper } from "../../Helpers/Functions";
import { useTreeBuild } from "../hooks/useTreeBuild";
import { useComponentDefaults } from "@lmb/kitsconcerto/Hooks";

const KitsTreeSelect = <T = any,>({ ref, ...rawProps }: ITreeSelect) => {
    const { mergedProps: props, themeStyle } = useComponentDefaults('TreeSelect', rawProps, 'Select');
    const {
        rightAddon,
        leftAddon,
        errors,
        invalid,
        label,
        id,
        placeholder,
        required,
        disabled,
        helperText,
        attached,
        isFloatedLabel,
        inputSize,
        valueMode,
        isMultiple,
        localProps,
        withFilter,
        filterBy,
        hideError,
        onlyParentsWithChildren,
        resetFilterOnHide,
        scrollHeight,
        emptyMessage,
        showClear,
    } = props;

    const { nodes, value, handleChange } = useTreeBuild<T>({
        isStructured: props.isStructured,
        ref,
    });

    const ClState = ClHelper({
        inputSize: inputSize ?? "",
        isChecked: false,
        isInvalid: !!invalid,
        isDisabled: !!disabled,
    });

    const Element = (
        <TreeSelect
            value={value}
            filter={withFilter}
            filterBy={filterBy}
            options={nodes}
            display={isMultiple ? valueMode : "comma"}
            onChange={handleChange}
            selectionMode={isMultiple ? 'checkbox' : 'single'}
            placeholder={placeholder}
            disabled={disabled}
            invalid={invalid}
            showClear={showClear ?? !required}
            isModal={false}
            onlyParentsWithChildren={onlyParentsWithChildren}
            resetFilterOnHide={resetFilterOnHide}
            scrollHeight={scrollHeight}
            emptyMessage={emptyMessage}
            style={Object.keys(themeStyle).length ? themeStyle : undefined}
            {...localProps}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
        >
            {Element}
        </KitsContainer>
    );
}
export default KitsTreeSelect;
